// // This D Flip-Flop has an active-low reset. When the reset signal is high, the output q is set to HIGH. Otherwise, q follows the input d.
module top_module(clk, rst, d, q);input clk;
input rst;
input d;
output q;

reg q;

always @(posedge clk) begin
    if (rst) begin
        q <= 1'b0;
    end else begin
        q <= d;
    end
end

endmodule
